INSERT INTO public.proc_line_narratives (proc_line_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$P_3010_L023$$, 2027, $$This effort will procure one C-40C aircraft to increase the fleet size from seven C-40Cs to eight C-40Cs. Funding for this effort was included in the FY26 appropriations bill as a program increase for one additional
 C-40C. The C-40C is a commercial derivative Boeing 737-700 twin engine, turbo fan aircraft used to airlift DoW officials and United States government personnel worldwide.

 Funding will be used to purchase a Boeing 737-700 and integrate the standard military-specific modifications and senior leader communications systems already present on the C-40C fleet. The funding will also
 support product support cost activities, program support costs; including advisory and assistance services, and other government costs.

 FY2025 was rescinded $10.000 million and is not reflected in this budget documentation.

 Funding for this exhibit contained in PE 0401314F

 Justification:
