INSERT INTO public.proc_line_narratives (proc_line_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$P_3010_L041$$, 2027, $$The Crewed Platform Integration program will procure and integrate 142 kits for F-22 installation which will allow for F-22 control of Collaborative Combat Aircraft (CCA). The procurement effort includes, but is
 not limited to, tablets, cables, and associated materials; activities associated with system integration, assembly, test and checkout; certification; aircraft and CCA communications integration; software updates;
 systems engineering; training; support equipment; and Program Support Costs (PSC).

 The FY 2026 spend plan amount for Aircraft Procurement includes 15,048 thousand of discretionary and 900 thousand of mandatory (reconciliation) for a total of 15,948 thousands.

 In Current Year (FY 2026) Crewed Platform Integration was a new start.

 Justification:
 The Crewed Platform Integration program is required for the F-22 fleet to integrate with and control Collaborative Combat Aircraft (CCA).$$, NULL, $$Exhibit P-40, Budget Line Item Justification: PB 2027 Air Force                                                                                                                Date: April 2026
